  Fw = /* @__PURE__ */ JSON.parse('[{"version":"v1.2.1","date":"2026-04-13","sections":[{"type":"added","items":["新增交互触发元数据持久化结构 `rollhelper_interactive_triggers_v1`，将 `rh-trigger` 从正文协议拆分为“纯文本正文 + 独立元数据”。","新增交互触发专用元数据处理模块，统一负责旧协议解析、正文清洗、刷新兼容与悬浮提示文案构建。"]},{"type":"changed","items":["重构交互触发渲染链路：不再依赖正文里的 `[[rh-trigger]]` 直接渲染，而是优先读取消息 `extra/swipe_info.extra` 中的触发元数据重建下划线与点击交互。","调整生成结束后的清洗流程，使 ROLLJSON 事件清洗与 `rh-trigger` 协议清洗在同一批后处理中执行，并补充延迟收尾以兼容酒馆正文最终写回时机。","更新交互触发提示内容：相同动作与技能不再重复展示，公开/暗骰状态前新增图标提示。"]},{"type":"improved","items":["修复助手回复与后续 Prompt、summary、memory 路径中残留 `rh-trigger` 协议文本的问题，避免交互标记继续污染模型上下文。","修复旧消息与刷新后的兼容性问题，历史楼层中的单层或双层 `rh-trigger` 标记现在都能被迁移清洗，并在刷新后稳定恢复下划线与悬浮提示。","修复桌面端交互触发体验：悬浮显示轻量 tooltip，点击再弹出动作菜单，避免提示与菜单状态错乱。","修复同词多次出现时的高亮定位问题，新增 occurrence 顺序定位后可更稳定地命中正确词语。","清理交互触发重构过程中的冗余重试与旧扫描逻辑，收敛为更稳定的消息后处理与 DOM 重建流程。"]}]},{"version":"v1.2.0","date":"2026-04-12","sections":[{"type":"added","items":["新增“启用 3D 骰子动画并用其结果结算”设置项，默认开启；开启后，普通掷骰、事件手动骰与 AI 自动骰统一由 dice-box 负责出点、动画与结果回传。","新增“启用重新投掷功能”设置项，默认关闭；开启后，可在事件结果卡中对已结算事件再次手动掷骰，并保留历史记录。","新增事件难度等级展示与难度驱动阈值换算链路，支持 AI 优先输出 easy、normal、hard、extreme，再由系统自动映射为可达的判定条件。"]},{"type":"changed","items":["重构 RollHelper 掷骰流程为 2D 与 3D 双模式分流：关闭 3D 时继续走旧的本地无动画链路，开启 3D 时统一以 dice-box 结果作为唯一结算真值，避免动画结果与结算结果不一致。","调整事件协议与提示约束，明确优劣骰是取最高或最低结果而非相加，并引导 AI 使用难度等级而不是直接编造不可达的达标值。","更新事件列表卡与结果卡信息结构，补充难度、阈值来源、优劣骰保留结果与重新投掷入口，让判定依据更直观。"]},{"type":"improved","items":["修复 D100 在事件骰场景中只校正一颗骰子的聚焦问题，双骰现在会作为同组一起围绕画布中心居中显示。","修复事件结算未读取 dice-box 实际结果的问题；现在画面中看到的百分骰、普通骰与结果卡总值保持一致。","修复楼层内容重置或替换后仍错误沿用旧骰子结果的问题，楼层版本变化后会重新对账并失效过期事件与旧记录。","优化 D100 双骰聚焦间距与结果说明，降低十位骰和个位骰贴得过近、看起来像普通求和的误解。","优化优劣骰结果展示，结果卡会明确标出取高或取低后的保留值与舍弃值，避免把 2d20kh1 或 2d20kl1 误读成双骰相加。","优化失败态结果卡样式，失败时总值与状态标签会使用更明显的红色反馈。","增强事件解析阶段的可达范围校验与提示，减少劣势检定却生成超高阈值的情况。","修复若干事件卡渲染、结果同步与楼层追踪相关的零散问题，提升复杂聊天流程下的稳定性。"]}]},{"version":"v1.1.8","date":"2026-03-21","sections":[{"type":"added","items":["SS-Helper 底层SDK升级。"]},{"type":"improved","items":["优化了楼层重roll残余旧数值的问题，确保重roll后事件卡片显示最新的骰子结果和状态变化。"]}]},{"version":"v1.1.7","date":"2026-03-17","sections":[{"type":"added","items":["为 SS-Helper-MemoryOS 插件进行了兼容。"]},{"type":"improved","items":["优化了技能编辑器在电脑模式下的UI，修复了手机模式下无法滚动的问题。"]}]},{"version":"v1.1.6","date":"2026-03-13","sections":[{"type":"added","items":["为事件卡片新增移动端模板与样式，补齐移动端列表卡、列表项、结算卡和结果卡布局。","新增移动端专用的事件列表卡、事件列表项、结算卡与结果卡 HTML 模板文件。"]},{"type":"changed","items":["收紧事件 ROLLJSON 提示约束，明确只有 checkDice 含 ! 时才允许输出 explode 分支，避免爆骰分支与骰式不一致。","调整设置页主题挂载范围，扩展列表标题条恢复跟随酒馆官方 inline-drawer 样式，仅内容区和弹窗继续使用 SDK 主题。"]},{"type":"improved","items":["优化卡片在手机端的渐变、排版与响应式展示，提升详情区可读性。","完善桌面与移动端卡片渲染衔接，为后续独立适配留出结构空间。","将 RollHelper 卡片内的 Tooltip 配色接入 SDK 主题系统，并放大相邻 Tooltip 目标间的平滑移动检测范围。","优化亮色主题下的设置页可读性，修正文本阴影、选中标签、共享复选框悬浮边框和更新日志面板层次表现。","为技能预设列表和状态编辑器侧栏名称补充超长文本跑马灯逻辑，宽度不足时自动滚动显示完整名称。"]}]},{"version":"v1.1.5","date":"2026-03-11","sections":[{"type":"added","items":["新增事件列表项模板与掷骰结果卡片模板，开始切换到新的事件卡片渲染链路。","新增 RollHelper 卡片测试页与 Vite 构建链路，并补充 Tailwind、PostCSS 与 CSS 类型声明。","新增共享 Changelog 组件，以及 SDK Tavern Prompt/Runtime 封装能力。"]},{"type":"changed","items":["将事件卡片样式拆分到 html/roll-cards 目录，改为模板文件加样式文件的组织方式。","重构设置页模板、事件渲染与部分运行时依赖，统一新的组件与主题接入方式。"]},{"type":"improved","items":["增强事件卡片预览、调试与测试输入能力，便于持续调样和验收。","优化事件列表项、结果卡和基础卡片样式细节，提升视觉一致性。"]}]},{"version":"v1.1.4","date":"2026-03-10","sections":[{"type":"added","items":["新增共享输入框与共享选择组件，支持统一样式、键盘交互和动态定位。","新增 SDK 设置管理、插件聊天状态接口与 Tavern ChatKey 生成能力。","新增设置页容器组件，并落地状态编辑器、技能编辑器与设置卡片拆分架构。","新增消息净化模块与历史清理工具，用于处理外部摘要和记忆插件带入的数据。"]},{"type":"changed","items":["将原有设置页逻辑拆分到 uiCard、uiTheme、statusEditor、skillEditor 等模块，降低耦合。","重构部分 Tavern SDK、主题能力与提示体系，统一设置页与组件层的调用入口。"]},{"type":"improved","items":["补强共享按钮、共享复选框与全局提示样式，使设置页控件外观更统一。","提升状态编辑与聊天维度存储链路的可维护性，为后续按聊天隔离数据打基础。"]}]},{"version":"v1.1.3","date":"2026-03-09","sections":[{"type":"added","items":["在设置卡片中新增主题选择项。"]},{"type":"improved","items":["更新设置卡片样式，支持默认、深色、浅色和酒馆主题。","优化复选框与主题变量映射，使设置页控件风格与主题系统保持一致。"]}]},{"version":"v1.1.2","date":"2026-03-03","sections":[{"type":"improved","items":["重构三类 Roll 卡片（当前事件、检定结果、已结算）为默认收起的可展开结构，摘要只展示关键字段，展开后查看完整详情。","当前事件卡收起态保留“执行检定”直达按钮，提升常用操作效率。","结果卡与结算卡摘要补充骰子可视化与关键信息（状态、总点、条件、来源），并同步完善渲染参数。","统一卡片按钮与交互样式，补齐展开状态指示、悬停反馈、结果区标题与骰子居中、移动端细节适配及 reduced-motion 兼容。","状态编辑器 UI 全面重构为左右分栏，支持聊天侧栏与右侧编辑区协同工作，并支持侧栏宽度与表格列宽拖拽。","聊天列表改为横向信息布局，补充头像、名称、最后聊天时间与 CHATID 展示，并完善中文化与长文本裁切。","优化滚动行为：左栏承担整体纵向滚动，右侧表格仅数据区滚动且表头固定，列宽拖拽手柄增加视觉提示。"]},{"type":"fixed","items":["修复 summary 内按钮误触发展开/收起的问题，确保检定操作与折叠交互互不干扰。"]},{"type":"changed","items":["状态数据改为按 chatKey 隔离存储与编辑：当前聊天保存即时生效，非当前聊天写入目标聊天，不再污染当前运行态。"]},{"type":"added","items":["新增 MemoryOS SDK Bus 集成，可探测安装与启用状态、读取 memory chat keys 并订阅状态广播；未安装或未启用时自动降级为本地模式。"]}]},{"version":"v1.1.1","date":"2026-03-03","sections":[{"type":"added","items":["新增手机分辨率适配。","新增状态修正功能，AI 可以设定角色状态并自动修正检定结果。","新增“系统动态规则注入 + 用户补充规则”机制，系统会按当前开关自动生成事件骰子协议，规则文本改为只填写补充内容。","新增聊天级持久化，技能预设与角色状态按聊天维度保存，切换聊天会自动装载对应配置。","新增状态持续轮次机制，支持 turns/duration 并在轮次切换时自动衰减与清理。","新增 SSHelper 输入区工具栏，支持“技能预览 / 状态预览”弹窗。"]},{"type":"improved","items":["升级爆骰策略，AI 自动检测每轮允许的爆骰事件数量，超出上限时自动降级为普通掷骰并记录原因。","重构事件卡片与结果卡样式，统一提示气泡、补充爆骰信息与状态变化摘要，并优化移动端展示。","增强设置页，新增“恢复默认预设”按钮，状态编辑器支持持续轮次输入并强化校验提示。"]}]}]');
